<?php
/**
 * fix-audit-improvements.php
 * Deploy: Authenticate middleware (force logout), PenggunaController (session invalidation),
 *         Dashboard tabs + stat context
 * NOTA: $root = __DIR__ kerana seluruh projek Laravel ada dalam /htdocs/ di InfinityFree
 * Run: https://ibookbptm.great-site.net/fix-audit-improvements.php?key=ibook2026deploy
 */
if (($_GET['key'] ?? '') !== 'ibook2026deploy') { http_response_code(403); exit('Forbidden'); }

$root = __DIR__;  // InfinityFree: /htdocs/ = web root = Laravel root

function deployFile($root, $rel, $b64) {
    $target = $root . '/' . $rel;
    $dir    = dirname($target);
    if (!is_dir($dir)) mkdir($dir, 0755, true);
    $bytes = base64_decode($b64);
    if ($bytes === false) { echo "ERR decode: $rel\n"; return; }
    if (file_put_contents($target, $bytes) === false) {
        echo "ERR write: $rel (perms: " . decoct(fileperms($dir) & 0777) . ")\n";
        return;
    }
    echo "OK  $rel (" . strlen($bytes) . " bytes)\n";
}

function clearBladeCache($root) {
    $dir = $root . '/storage/framework/views';
    if (!is_dir($dir)) { echo "SKIP blade cache (dir tiada: $dir)\n"; return; }
    $n = 0;
    foreach (glob($dir . '/*.php') as $f) { @unlink($f); $n++; }
    echo "OK  blade cache dibersihkan ($n fail)\n";
}

function deletePublicFile($root, $name) {
    $path = $root . '/' . $name;
    if (file_exists($path)) { @unlink($path); echo "DEL $name\n"; }
    else echo "SKIP $name (tidak wujud)\n";
}

header('Content-Type: text/plain; charset=utf-8');
echo "=== fix-audit-improvements.php ===\n";
echo "Masa: " . date('Y-m-d H:i:s') . "\n";
echo "Root: $root\n\n";

$files = [
    'app/Http/Middleware/Authenticate.php' => '',
    'app/Http/Controllers/PenggunaController.php' => '',
    'resources/views/dashboard/index.blade.php' => '',
];

foreach ($files as $rel => $b64) {
    deployFile($root, $rel, $b64);
}

echo "\n--- Membersihkan fail diagnostik lama ---\n";
$diagnostik = [
    'fix-recovery.php','fix-security.php','fix-2fa.php',
    'diag-berulang.php','diag2-berulang.php',
    'chk-index.php','fix-index.php','fix-index2.php',
    'patch-server.php','fix-sehari-penuh.php',
];
foreach ($diagnostik as $d) { deletePublicFile($root, $d); }

echo "\n--- Membersihkan blade cache ---\n";
clearBladeCache($root);

echo "\n=== SELESAI ===\n";
echo "Fail ini akan dipadam sendiri...\n";
@unlink(__FILE__);
echo "Dipadam: " . basename(__FILE__) . "\n";